+    const nestedPath = path.resolve(
+      path.dirname(normalizedPath),
+      specifier.replace(/\.js$/, ".ts"),
+    );
+    const nestedExports = await collectRuntimeExports(nestedPath, seen);
+    for (const name of nestedExports) {
+      exportNames.add(name);
+    }
+  }
+
+  return exportNames;
+}

