+    ...(extensionApiAlias ? { "openclaw/extension-api": extensionApiAlias } : {}),
+    ...(pluginSdkAlias ? { "openclaw/plugin-sdk": pluginSdkAlias } : {}),
+    ...resolvePluginSdkScopedAliasMap({ modulePath }),
+  };
+}
